exercise.solutionCode:
const fullName = "  Rahul Sharma  ";

const trimmed  = fullName.trim();
const lower    = trimmed.toLowerCase();
const username = lower.replaceAll(" ", "_");

console.log("Original:", trimmed);
console.log("Username:", username);
